gcontent-%COMP%] { background-color: rgba(52, 152, 219, 0.1); }\n.category-entertainment[_ngcontent-%COMP%] { background-color: rgba(155, 89, 182, 0.1); }\n.category-utilities[_ngcontent-%COMP%] { background-color: rgba(230, 126, 34, 0.1); }\n.category-maintenance[_ngcontent-%COMP%] { background-color: rgba(231, 76, 60, 0.1); }\n.category-marketing[_ngcontent-%COMP%] { background-color: rgba(26, 188, 156, 0.1); }\n.category-supplies[_ngcontent-%COMP%] { background-color: rgba(149, 165, 166, 0.1); }\n.category-other[_ngcontent-%COMP%] { background-color: rgba(44, 62, 80, 0.1); }\n\n\n\n.no-data[_ngcontent-%COMP%] {\n  text-align: center;\n  padding: var(--spacing-xl);\n  color: var(--text-secondary);\n}\n\n.no-data[_ngcontent-%COMP%]   p[_ngcontent-%COMP%] {\n  margin: 0;\n  font-size: var(--font-size-lg);\n}\n\n\n\n.btn[_ngcontent-%COMP%] {\n  padding: var(--spacing-sm) var(--spacing-md);\n  border: none;\n  border-radius: var(--border-radius);\n  cursor: pointer;\n  font-size: var(--font-size-base);\n  font-weight: 500;\n  transition: all 0.2s;\n  text-decoration: none;\n  display: inline-block;\n}\n\n.btn-primary[_ngcontent-%COMP%] {\n  background-color: var(--accent-color);\n  color: white;\n}\n\n.btn-primary[_ngcontent-%COMP%]:hover {\n  background-color: #2980b9;\n  transform: translateY(-1px);\n}\n\n.btn-primary[_ngcontent-%COMP%]:disabled {\n  background-color: var(--text-muted);\n  cursor: not-allowed;\n  transform: none;\n}\n\n.btn-secondary[_ngcontent-%COMP%] {\n  background-color: var(--bg-secondary);\n  color: var(--text-primary);\n  border: 1px solid var(--border-color);\n}\n\n.btn-secondary[_ngcontent-%COMP%]:hover {\n  background-color: var(--bg-tertiary);\n}\n\n\n\n@media (max-width: 768px) {\n  .expenses-container[_ngcontent-%COMP%] {\n    padding: var(--spacing-md);\n  }\n\n  .header[_ngcontent-%COMP%] {\n    flex-direction: column;\n    gap: var(--spacing-md);\n    align-items: stretch;\n  }\n\n  .filters-section[_ngcontent-%COMP%] {\n    flex-dir